import React, { useEffect, useState } from "react";
import { Link } from 'react-router-dom';
import { CButton } from "@coreui/react";
import { customStyles } from "../../../utils/tableCustomStyles";
import DataTable from "react-data-table-component";
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal, showConfirmAlertPopUp } from "src/utils/Common";
import { tableSubscriptionPlanConstant } from "../tableSubscriptionPlanConstant";
import { deleteSubscriptionPlan, getSubscriptionPlaneList } from "src/components/services/SubscriptionPlanApi";
import authService from "src/auth/auth.service";

const MySwal = withReactContent(alertPopUp);


const SubscriptionPlanList = () => {
    const [rowData, setRowData] = useState([]);

    useEffect(() => {
        fetchSubscriptionPlaneList();
    }, []);

    const fetchSubscriptionPlaneList = async () => {
        const response = await getSubscriptionPlaneList();
        if (response?.status === "200 OK") {
            setRowData(response?.body);
        }
    };

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDeletePrduct(id)
            }
        };
        handleConfirm();
    };

    const handleDeletePrduct = async(id) => {
        const response = await deleteSubscriptionPlan(id);
        if(response?.status === "202 ACCEPTED"){
            fetchSubscriptionPlaneList();
        }
        if(response?.status === "409 CONFLICT"){
            const handleConfirm = async () => {
                await MySwal.fire(showConfirmAlertPopUp(response?.message));
            };
            handleConfirm()
        };
    }

    return (
        <div className='row'>
            <div className="col2Large">
                <DataTable
                    title="Subscription Plans"
                    columns={tableSubscriptionPlanConstant(fetchSubscriptionPlaneList,handleConfirmModal)}
                    data={rowData}
                    customStyles={customStyles}
                    pagination
                    paginationPerPage={10}
                    pointerOnHover
                    fixedHeader
                    noContextMenu
                    fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                />
            </div>

            {authService.getPermission("SUBSCRIPTION_PLAN_CREATE") && 
                <div className='col-sm-12'>
                    <Link to={"/subcription-plan/create"}>
                        <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                            {"+ Create Plan"}
                        </CButton>
                    </Link>
                </div>}
        </div>
    );
}

export default SubscriptionPlanList;
